### Steps to reproduce

  1. Run an app with a TextField with some text in it and spell check enabled (see sample below).
  2. Focus the TextField.

### Expected results

Misspelled words are underlined.

### Actual results

Nothing is underlined unless the user starts typing.

### Code sample

<details><summary>Code sample</summary>

```dart
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Demo',
      home: MyHomePage(),
    );
  }
}

class MyHomePage extends StatelessWidget {
  MyHomePage({super.key});

  final TextEditingController controller = TextEditingController(text: 'To be or not to be, that is the question.');

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('SpellCheckService Bug')),
      body: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          children: [
            TextField(
              controller: controller,
              spellCheckConfiguration: SpellCheckConfiguration(
                spellCheckService: EverythingWrongSpellCheckService(),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

// SpellCheckService that always marks every word as misspelled.
class EverythingWrongSpellCheckService extends SpellCheckService {
  @override
  Future<List<SuggestionSpan>?> fetchSpellCheckSuggestions(Locale locale, String text) async {
    final matches = RegExp(r'\b\w+').allMatches(text);
    return matches
        .map((match) => SuggestionSpan(
              TextRange(start: match.start, end: match.end),
              const [],
            ))
        .toList();
  }
}
```

